SELECT team_id, AVG(wins) AS average_wins
FROM playoffs
GROUP BY team_id;

SELECT SUM(points_won) AS total_points_won_in_season_1
FROM player_seasons
WHERE season_id = 1;

SELECT p.player_name
FROM players p
JOIN game_logs g ON p.player_id = g.player_id
WHERE g.points = (
    SELECT MAX(points) FROM game_logs
);

SELECT p.player_name, p.age
FROM players p
JOIN player_seasons ps ON p.player_id = ps.player_id
WHERE ps.season_id = (
    SELECT MIN(season_id) FROM seasons
) AND ps.points_won = (
    SELECT MAX(points_won) FROM player_seasons
    WHERE season_id = (
        SELECT MIN(season_id) FROM seasons
    )
);

SELECT COUNT(*)
FROM draft_picks
WHERE draft_year = 2023;
